changeSet.sql:
CREATE TABLE nexus.tier_writes (
    id           BIGSERIAL    NOT NULL,
    tenant_id    TEXT         NOT NULL,
    session_id   TEXT         NOT NULL,
    ts           TIMESTAMPTZ  NOT NULL,
    tool         TEXT         NOT NULL,
    tier         TEXT         NOT NULL,
    agent        TEXT,
    project      TEXT,
    target_title TEXT,
    CONSTRAINT tier_writes_pk PRIMARY KEY (id)
);

-- BTree indexes: nx tier-status queries by session_id + ts; time-window scans
CREATE INDEX idx_tier_writes_ts      ON nexus.tier_writes (tenant_id, ts DESC);
CREATE INDEX idx_tier_writes_session ON nexus.tier_writes (tenant_id, session_id, ts DESC);
CREATE INDEX idx_tier_writes_tool    ON nexus.tier_writes (tenant_id, tool);

-- ETL dedup: same (session, ts, tool, tier) within a tenant = same event
CREATE UNIQUE INDEX idx_tier_writes_etl_dedup
    ON nexus.tier_writes (tenant_id, session_id, ts, tool, tier);

ALTER TABLE nexus.tier_writes ENABLE ROW LEVEL SECURITY;
ALTER TABLE nexus.tier_writes FORCE ROW LEVEL SECURITY;
CREATE POLICY tenant_isolation ON nexus.tier_writes
    USING      (tenant_id = current_setting('nexus.tenant', true))
    WITH CHECK (tenant_id = current_setting('nexus.tenant', true));

changeSet.rollback:
DROP POLICY IF EXISTS tenant_isolation ON nexus.tier_writes;
ALTER TABLE nexus.tier_writes NO FORCE ROW LEVEL SECURITY;
ALTER TABLE nexus.tier_writes DISABLE ROW LEVEL SECURITY;

changeSet.sql:
CREATE TABLE nexus.nx_answer_runs ( id BIGSERIAL NOT NULL, tenant_id TEXT NOT NULL, question TEXT NOT NULL, plan_id BIGINT, matched_confidence DOUBLE PRECISION, step_count INTEGER NOT NULL DEFAULT 0, final_text TEXT NOT NULL DEFAULT '', cost_usd DOUBLE PRECISION NOT NULL DEFAULT 0.0, duration_ms BIGINT NOT NULL DEFAULT 0, created_at TIMESTAMPTZ NOT NULL, CONSTRAINT nx_answer_runs_pk PRIMARY KEY (id) );
-- BTree index on created_at for time-range queries and ordering CREATE INDEX idx_nx_answer_runs_ts ON nexus.nx_answer_runs (tenant_id, created_at DESC); CREATE INDEX idx_nx_answer_runs_plan_id ON nexus.nx_answer_runs (tenant_id, plan_id);
-- ETL dedup: same question at same timestamp from same tenant = same run CREATE UNIQUE INDEX idx_nx_answer_runs_etl_dedup ON nexus.nx_answer_runs (tenant_id, question, created_at);

ALTER TABLE nexus.nx_answer_runs ENABLE ROW LEVEL SECURITY;
ALTER TABLE nexus.nx_answer_runs FORCE ROW LEVEL SECURITY;
CREATE POLICY tenant_isolation ON nexus.nx_answer_runs
    USING      (tenant_id = current_setting('nexus.tenant', true))
    WITH CHECK (tenant_id = current_setting('nexus.tenant', true));

changeSet.rollback:
DROP POLICY IF EXISTS tenant_isolation ON nexus.nx_answer_runs;
ALTER TABLE nexus.nx_answer_runs NO FORCE ROW LEVEL SECURITY;
ALTER TABLE nexus.nx_answer_runs DISABLE ROW LEVEL SECURITY;

changeSet.sql:
CREATE TABLE nexus.hook_failures ( id BIGSERIAL NOT NULL, tenant_id TEXT NOT NULL, doc_id TEXT NOT NULL DEFAULT '', collection TEXT NOT NULL DEFAULT '', hook_name TEXT NOT NULL, error TEXT NOT NULL DEFAULT '', occurred_at TIMESTAMPTZ NOT NULL DEFAULT now(), batch_doc_ids TEXT, is_batch INTEGER NOT NULL DEFAULT 0, chain TEXT NOT NULL DEFAULT 'single', CONSTRAINT hook_failures_pk PRIMARY KEY (id) );
-- BTree indexes: nx doctor hooks queries "WHERE occurred_at >= ?" + collection scoping CREATE INDEX idx_hook_failures_ts ON nexus.hook_failures (tenant_id, occurred_at DESC); CREATE INDEX idx_hook_failures_collection ON nexus.hook_failures (tenant_id, collection, occurred_at DESC);
-- ETL dedup: same doc+hook+timestamp within a tenant = same failure event CREATE UNIQUE INDEX idx_hook_failures_etl_dedup ON nexus.hook_failures (tenant_id, doc_id, hook_name, occurred_at);

ALTER TABLE nexus.hook_failures ENABLE ROW LEVEL SECURITY;
ALTER TABLE nexus.hook_failures FORCE ROW LEVEL SECURITY;
CREATE POLICY tenant_isolation ON nexus.hook_failures
    USING      (tenant_id = current_setting('nexus.tenant', true))
    WITH CHECK (tenant_id = current_setting('nexus.tenant', true));

changeSet.rollback:
DROP POLICY IF EXISTS tenant_isolation ON nexus.hook_failures;
ALTER TABLE nexus.hook_failures NO FORCE ROW LEVEL SECURITY;
ALTER TABLE nexus.hook_failures DISABLE ROW LEVEL SECURITY;

changeSet.sql:
CREATE TABLE nexus.frecency (
    tenant_id      TEXT             NOT NULL,
    chunk_id       TEXT             NOT NULL,
    embedded_at    TIMESTAMPTZ      NOT NULL DEFAULT now(),
    ttl_days       INTEGER          NOT NULL DEFAULT 0,
    frecency_score DOUBLE PRECISION NOT NULL DEFAULT 0,
    miss_count     INTEGER          NOT NULL DEFAULT 0,
    last_hit_at    TIMESTAMPTZ      NOT NULL DEFAULT now(),
    CONSTRAINT frecency_pk PRIMARY KEY (tenant_id, chunk_id)
);

-- BTree indexes: frecency-only re-index scans by chunk_id
CREATE INDEX idx_frecency_chunk        ON nexus.frecency (tenant_id, chunk_id);
CREATE INDEX idx_frecency_last_hit     ON nexus.frecency (tenant_id, last_hit_at DESC);
CREATE INDEX idx_frecency_score        ON nexus.frecency (tenant_id, frecency_score DESC);

ALTER TABLE nexus.frecency ENABLE ROW LEVEL SECURITY;
ALTER TABLE nexus.frecency FORCE ROW LEVEL SECURITY;
CREATE POLICY tenant_isolation ON nexus.frecency
    USING      (tenant_id = current_setting('nexus.tenant', true))
    WITH CHECK (tenant_id = current_setting('nexus.tenant', true));

changeSet.rollback:
DROP POLICY IF EXISTS tenant_isolation ON nexus.frecency;
ALTER TABLE nexus.frecency NO FORCE ROW LEVEL SECURITY;
ALTER TABLE nexus.frecency DISABLE ROW LEVEL SECURITY;

changeSet.sql:
DO $$
BEGIN
    IF EXISTS (SELECT 1 FROM pg_roles WHERE rolname = 'nexus_svc') THEN
        EXECUTE 'GRANT SELECT, INSERT, UPDATE, DELETE ON nexus.relevance_log    TO nexus_svc';
        EXECUTE 'GRANT USAGE ON SEQUENCE nexus.relevance_log_id_seq             TO nexus_svc';
        EXECUTE 'GRANT SELECT, INSERT, UPDATE, DELETE ON nexus.search_telemetry TO nexus_svc';
        EXECUTE 'GRANT SELECT, INSERT, UPDATE, DELETE ON nexus.tier_writes       TO nexus_svc';
        EXECUTE 'GRANT USAGE ON SEQUENCE nexus.tier_writes_id_seq               TO nexus_svc';
        EXECUTE 'GRANT SELECT, INSERT, UPDATE, DELETE ON nexus.nx_answer_runs   TO nexus_svc';
        EXECUTE 'GRANT USAGE ON SEQUENCE nexus.nx_answer_runs_id_seq            TO nexus_svc';
        EXECUTE 'GRANT SELECT, INSERT, UPDATE, DELETE ON nexus.hook_failures    TO nexus_svc';
        EXECUTE 'GRANT USAGE ON SEQUENCE nexus.hook_failures_id_seq             TO nexus_svc';
        EXECUTE 'GRANT SELECT, INSERT, UPDATE, DELETE ON nexus.frecency         TO nexus_svc';
        RAISE NOTICE 'Granted telemetry table privileges to nexus_svc';
    ELSE
        RAISE NOTICE 'nexus_svc role not found; skipping grants (create role before first run)';
    END IF;
END
$$;
